// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-crea-cita
const input = $input.first().json;

// Extraer datos
const fecha_inicio = input.fecha_inicio;
const fecha_fin = input.fecha_fin;
let patente = input.patente;

// VALIDACIONES
const errores = [];

// 1. VALIDAR FECHA INICIO (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!fecha_inicio || !regexFecha.test(fecha_inicio)) {
  errores.push(`Fecha inicio inválida: "${fecha_inicio}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// 2. VALIDAR FECHA FIN (YYYY-MM-DD)
if (!fecha_fin || !regexFecha.test(fecha_fin)) {
  errores.push(`Fecha fin inválida: "${fecha_fin}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// 3. VALIDAR QUE FECHA_INICIO < FECHA_FIN
if (fecha_inicio && fecha_fin && regexFecha.test(fecha_inicio) && regexFecha.test(fecha_fin)) {
  const dateInicio = new Date(fecha_inicio);
  const dateFin = new Date(fecha_fin);

  if (dateInicio >= dateFin) {
    errores.push(`La fecha de inicio (${fecha_inicio}) debe ser anterior a la fecha de fin (${fecha_fin})`);
  }
}

// 4. Verificar que patente existe y no es nulo/undefined
if (!patente || patente === null || patente === undefined) {
  errores.push("La patente es obligatoria y no puede ser nula");
}

// Si la patente existe, proceder con limpieza y validaciones
if (patente) {
  // Convertir a string si no lo es
  patente = String(patente);

  // Limpiar: quitar espacios, guiones y caracteres especiales
  patente = patente.trim()
                   .replace(/[-\s_./]/g, '')
                   .toUpperCase();

  // Verificar que no quedó vacía después de limpiar
  if (patente.length === 0) {
    errores.push("La patente no puede estar vacía después de limpiar");
  }

  // Validar longitud (patentes argentinas: 6 o 7 caracteres)
  //if (patente.length < 6 || patente.length > 7) {
  //  errores.push(`La patente debe tener 6 o 7 caracteres (recibido: ${patente.length})`);
  //}

  // Validar que solo contenga letras y números
  const soloAlfanumerico = /^[A-Z0-9]+$/;
  if (!soloAlfanumerico.test(patente)) {
    errores.push("La patente solo puede contener letras y números");
  }

  // Validación de formato argentino
  //const formatoViejo = /^[A-Z]{3}[0-9]{3}$/;
  //const formatoNuevo = /^[A-Z]{2}[0-9]{3}[A-Z]{2}$/;
  //
  //if (!formatoViejo.test(patente) && !formatoNuevo.test(patente)) {
    //errores.push(`Formato de patente inválido. Debe ser ABC123 o AB123CD (recibido: ${patente})`);
  //}
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        fecha_inicio,
        fecha_fin,
        patente_original: input.patente,
        patente_limpia: patente || null
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    fecha_inicio,
    fecha_fin,
    patente: patente,
    patente_original: input.patente
  }
}];

// Procesar respuesta de consulta de citas por patente
const response = $input.first().json;

// Verificar si la consulta fue exitosa
const exitoso = response.ResponseResult === 0;

if (exitoso) {
  // Verificar si InternalObject es un array o un objeto único
  const citasData = Array.isArray(response.InternalObject) 
    ? response.InternalObject 
    : [response.InternalObject];

  // Mapear todas las citas encontradas
  const citas = citasData.map(cita => ({
    citaId: cita.DOC_ID || null,
    servicio: cita.SERVICIO || null,
    fecha: cita.FECHA || null,
    hora: cita.HORA || null,
    marca: cita.MARCA || null,
    modelo: cita.MODELO || null,
    patente: cita.VEHICULO || null,
    taller: cita.TITULAR || null,
    telefono: cita.TELEFONO || null,
    asunto: cita.SUBJECT || null
  }));

  // Consulta exitosa - citas encontradas
  return {
    json: {
      exitoso: true,
      mensaje: `Se encontraron ${citas.length} cita(s)`,
      cantidadCitas: citas.length,
      citas: citas,
      // Parámetros de búsqueda usados
      parametrosBusqueda: {
        fechaInicio: $('validar-formato').first().json.fecha_inicio,
        fechaFin: $('validar-formato').first().json.fecha_fin,
        patenteBuscada: $('validar-formato').first().json.patente
      }
    }
  };
} else {
  // No se encontraron citas o hubo error
  return {
    json: {
      exitoso: false,
      mensaje: "No se encontraron citas o error en la consulta",
      codigoError: response.ResponseResult,
      tipoError: response.ExceptionType || "Desconocido",
      detalleError: response.ExceptionMessage || "Sin detalles",
      informacionAdicional: response.ExceptionInfo || null,
      // Parámetros de búsqueda usados
      parametrosBusqueda: {
        fechaInicio: $('validar-formato').first().json.fecha_inicio,
        fechaFin: $('validar-formato').first().json.fecha_fin,
        patenteBuscada: $('validar-formato').first().json.patente
      }
    }
  };
}

// Procesar salida con error de validación
const errorData = $input.first().json;

return [{
  json: {
    exitoso: false,
    tipoError: errorData.error || "ERROR_DESCONOCIDO",
    mensaje: "No se pudo consultar las citas debido a errores de validación",
    errores: errorData.errores || [],
    cantidadErrores: (errorData.errores || []).length,
    datosRecibidos: {
      fechaInicio: errorData.datos_recibidos?.fecha_inicio || null,
      fechaFin: errorData.datos_recibidos?.fecha_fin || null,
      patenteOriginal: errorData.datos_recibidos?.patente_original || null,
      patenteLimpia: errorData.datos_recibidos?.patente_limpia || null
    },
    timestamp: new Date().toISOString()
  }
}];
